import { Injectable, inject, signal, computed } from '@angular/core';
import { MPageService } from '@clinicaloffice/mpage-developer';
import { ConfigurationService } from './configuration.service';
import {
  ALL_TABS,
  TabDefinition,
  AppointmentTypeGroup,
  SuperuserGroupOverride,
  SUPERUSER_OVERRIDE_ALL
} from '../models/schedule.model';

@Injectable({ providedIn: 'root' })
export class AccessControlService {
  private readonly mPage = inject(MPageService);
  private readonly configService = inject(ConfigurationService);

  private readonly _positionReady = signal(false);
  private readonly _superuserGroupOverride = signal<SuperuserGroupOverride>(null);

  readonly userPosition = computed(() => {
    this._positionReady();
    return this.mPage.position ?? '';
  });

  readonly isConfigLoaded = computed(() => this.configService.isLoaded());

  readonly isSuperuser = computed(() => {
    const accessControl = this.configService.configuration()?.ACCESS_CONTROL;
    if (!accessControl) return this.isConfigLoaded();
    return accessControl.superusers.includes(this.userPosition());
  });

  readonly allowedTabs = computed((): TabDefinition[] => {
    const accessControl = this.configService.configuration()?.ACCESS_CONTROL;
    if (!accessControl) return this.isConfigLoaded() ? ALL_TABS : [];
    if (this.isSuperuser()) return ALL_TABS;

    const position = this.userPosition();
    return ALL_TABS.filter(tab => {
      const tabConfig = accessControl.tabs[tab.key];
      return tabConfig?.positions.includes(position) ?? false;
    });
  });

  readonly userGroup = computed<AppointmentTypeGroup | null>(() => {
    const position = this.userPosition();
    if (!position) return null;
    const groups = this.configService.configuration()?.APPOINTMENT_TYPE_GROUPS ?? [];
    return groups.find(g => g.positions.includes(position)) ?? null;
  });

  readonly hasScheduleAccess = computed<boolean>(
    () => this.isSuperuser() || this.userGroup() !== null
  );

  readonly superuserGroupOverride = this._superuserGroupOverride.asReadonly();

  readonly resolvedAppointmentTypes = computed<number[]>(() => {
    if (this.isSuperuser()) {
      const override = this._superuserGroupOverride();
      if (override === SUPERUSER_OVERRIDE_ALL) return this.unionOfAllGroups();
      if (override) {
        const grp = this.configService.configuration()?.APPOINTMENT_TYPE_GROUPS
          ?.find(g => g.id === override);
        if (grp) return grp.appointment_types;
      }
      return this.userGroup()?.appointment_types ?? this.unionOfAllGroups();
    }
    return this.userGroup()?.appointment_types ?? [];
  });

  readonly activeGroupLabel = computed<string>(() => {
    if (this.isSuperuser()) {
      const override = this._superuserGroupOverride();
      if (override === SUPERUSER_OVERRIDE_ALL) return 'All groups';
      if (override) {
        const grp = this.configService.configuration()?.APPOINTMENT_TYPE_GROUPS
          ?.find(g => g.id === override);
        if (grp) return grp.label;
      }
      return this.userGroup()?.label ?? 'All groups';
    }
    return this.userGroup()?.label ?? '';
  });

  resolvePosition(): void {
    this._positionReady.set(true);
  }

  setSuperuserGroupOverride(value: SuperuserGroupOverride): void {
    this._superuserGroupOverride.set(value);
  }

  canAccessTab(tabKey: string): boolean {
    const accessControl = this.configService.configuration()?.ACCESS_CONTROL;
    if (!accessControl) return this.isConfigLoaded();
    if (this.isSuperuser()) return true;
    const tabConfig = accessControl.tabs[tabKey];
    return tabConfig?.positions.includes(this.userPosition()) ?? false;
  }

  private unionOfAllGroups(): number[] {
    const groups = this.configService.configuration()?.APPOINTMENT_TYPE_GROUPS ?? [];
    return Array.from(new Set(groups.flatMap(g => g.appointment_types)));
  }
}
